const { exec } = require('child_process');
const os = require('os');

// Function to check if a process is running
function isProcessRunning(processName, callback) {
  // Determine the command based on the operating system
  const platform = os.platform();
  let cmd;

  if (platform === 'win32') {
    // Windows: Use tasklist to list all processes
    cmd = `tasklist`;
  } else {
    // Unix/Linux/Mac: Use ps to list all processes
    cmd = `ps -A`;
  }

  // Execute the command to list processes
  exec(cmd, (error, stdout, stderr) => {
    if (error) {
      return callback(error, null);
    }
    if (stderr) {
      return callback(new Error(stderr), null);
    }

    // Check if the process name exists in the output
    const isRunning = stdout.toLowerCase().includes(processName.toLowerCase());
    callback(null, isRunning);
  });
}
